############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "niceTables.pl", "parserRadioButtons.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
############################################################ # Header ############################################################ TEXT(beginproblem());
############################################################ # PG Setup Code ############################################################ Context("LimitedNumeric"); $yesno=RadioButtons([ "So -3 is a solution to this equation.", "So -3 is not a solution to this equation.", ], 0, showInStatic => 0 );
############################################################ # Body ############################################################
BEGIN_PGML Is [`-3`] a solution to the equation [`x^2+x+1=\frac{3x+2}{x+2}\text{?}`]
>> [@DataTable( [ [PGML('[`x^2+x+1`]'), PGML('[`{}={}`]'), PGML('[`\dfrac{3x+2}{x+2}`]'), ], [PGML('[_]{7}{2}'), PGML('[`{}\wonder{=}{}`]'), PGML('[_]{7}{2}'), ], ], align => 'rcl', valign => 'middle',);@]* <<
[_]{$yesno}{5}
END_PGML
############################################################ # Solution ############################################################
BEGIN_PGML_SOLUTION We have to substitute [`-3`] in for [`x`] and simplify each side:
[```\newcommand{\highlight}[1]{\mathchoice{\colorbox{lightsapphire}{$\displaystyle #1$}}{\colorbox{lightsapphire}{$\textstyle #1$}}{\colorbox{lightsapphire}{$\scriptstyle #1$}}{\colorbox{lightsapphire}{$\scriptscriptstyle #1$}}}\newcommand{\substitute}[1]{{\color{blue}{{#1}}}}\newcommand{\confirm}[1]{\stackrel{\checkmark}{#1}}\newcommand{\wonder}[1]{\stackrel{\text{?}}{#1}}\newcommand{\amp}{&} \begin{aligned} x^2+x+1\amp=\frac{3x+2}{x+2}\\ (\substitute{-3})^2+(\substitute{-3})+1\amp\wonder{=}\frac{3(\substitute{-3})+2}{\substitute{-3}+2}\\ \highlight{9}-3+1\amp\wonder{=}\frac{\highlight{-9}+2}{\highlight{-1}}\\ \highlight{6}+1\amp\wonder{=}\frac{\highlight{-7}}{-1}\\ \highlight{7}\amp\confirm{=}\highlight{7} \end{aligned} ```]
Since [`7=7`] is true, [`-3`] is indeed a solution to this equation.
END_PGML_SOLUTION
